queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?graphic_designers a :Graphic_Designers .
    ?graphic_designers p:name ?name .
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?web_developers a :Web_Developers .
    ?web_developers p:name ?name .
    ?web_developers p:office ?office_f .
    FILTER(STR(?office_f) = "2/7 London Street")
    BIND(?name AS ?o0)
  }
}

